import{_ as r,o as t,c as n,j as e,a as s,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.9.朝生暮死","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.9.朝生暮死.md","filePath":"1.基础规则/3.战斗规则/3.9.朝生暮死.md"}'),o={name:"1.基础规则/3.战斗规则/3.9.朝生暮死.md"};function d(l,a,p,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_3-9-朝生暮死",tabindex:"-1"},[s("3.9.朝生暮死 "),e("a",{class:"header-anchor",href:"#_3-9-朝生暮死","aria-label":'Permalink to "3.9.朝生暮死"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),_('<h1 id="朝生暮死" tabindex="-1">朝生暮死 <a class="header-anchor" href="#朝生暮死" aria-label="Permalink to &quot;朝生暮死&quot;">​</a></h1><p>朝生暮死</p><p><em>朝生</em><br> 在影片中受伤/承受异常点数的轮回者可以在影片结束后回到主神空间中进行治愈，前提为这些伤害/异常点数不是不可豁免不可抵抗不可治愈永久存在的。严重伤害、一档异常点数（包括冲击点数）无需支付分数；韧性伤害、二档异常点、属性降低每点50分；三档异常点每点250分。若轮回者在回到主神空间时的异常状态已达到毁灭等级，则还需要额外支付500分解除毁灭状态。</p><p>_暮死<br> _又称买活规则。在一场影片内，当某位轮回者死亡时，可以将其遗体（或一部分）保存好，并在影片结束时带回空间内，花费分数或经验将其复活。<br> 根据情况不同，依照下列规则进行查算和买活。<br> ●统计所有死前受到的严重伤害及异常点（包括一、二、三、四档，包括冲击点数），支付每点严重伤害/二档异常点/属性降低*250分（无需支付溢出部分，下同），支付每点一档异常点数50分，支付每点三档异常点数500分。<br> ●评估遗体完好程度，保留遗体的100%无需额外付款，保留90%需支付3XP，每下降10%额外支付3XP，此时不足10%按照10%计算。若遗体存留量不足10%，则视为无法复活。<br> ●若在影片内死于某种无法医治的疾病或病毒，则需选择一种当前人物支线等级最高的内在强化放弃，视为被主神回档到上一次备份的状态，并视为治愈了这种疾病（具体由ST定义），并正常买活。若放弃后人物的支线等级不再是原来的支线等级，则超出的技能部分视为暂时封存直至重新成为那个等级。也可以在放弃时选择支付等同于那项强化花费的经验数而不放弃强化。<br> ●若在影片内被杀死，且被施加了不可复活效果，则同理需选择一种当前人物支线等级最高的内在强化放弃，视为被主神回档到上一次备份的状态，并视为摆脱了不可复活的限制，并正常买活。若放弃后人物的支线等级不再是原来的支线等级，则超出的技能部分视为暂时封存直至重新成为那个等级。也可以在放弃时选择支付等同于那项强化花费的经验数而不放弃强化。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
